mapper.select:
SELECT d.ID, d.DEVICE_ID AS deviceId, d.PRODUCT_ID AS productId, p.NAME AS productName, d.NAME AS name, d.LOCATION AS location, d.STATUS AS status, d.LAST_ONLINE_TIME AS lastOnlineTime, d.FIRMWARE_VERSION AS firmwareVersion, d.TAGS AS tags, d.CREATED_DATE AS createdDate FROM dm_device d LEFT JOIN dm_product p ON d.PRODUCT_ID = p.ID
AND d.DEVICE_ID LIKE CONCAT('%', #{deviceId}, '%')
AND d.PRODUCT_ID = #{productId}
AND d.STATUS = #{status}
ORDER BY d.CREATED_DATE DESC

SELECT COUNT(1)
FROM dm_device
WHERE PRODUCT_ID = #{productId}
